import numpy as np

def feature_scaling(data: np.ndarray) -> (np.ndarray, np.ndarray):
    data = np.array(data, dtype=float)

    # Standardization (Z-score normalization)
    means = [sum(data[:, j]) / len(data[:, j]) for j in range(data.shape[1])]
    stds = [
        (sum((data[:, j] - means[j]) ** 2) / len(data[:, j])) ** 0.5
        for j in range(data.shape[1])
    ]
    standardized_data = np.array([
        [
            round((data[i, j] - means[j]) / stds[j], 4) if stds[j] != 0 else 0.0
            for j in range(data.shape[1])
        ]
        for i in range(data.shape[0])
    ])

    # Min-Max Normalization
    mins = [min(data[:, j]) for j in range(data.shape[1])]
    maxs = [max(data[:, j]) for j in range(data.shape[1])]
    normalized_data = np.array([
        [
            round((data[i, j] - mins[j]) / (maxs[j] - mins[j]), 4) if maxs[j] != mins[j] else 0.0
            for j in range(data.shape[1])
        ]
        for i in range(data.shape[0])
    ])

    return standardized_data, normalized_data
